#include <stdio.h>
#include <limits.h>
int min(int a, int b) { return a < b ? a : b; }
int main() {
    int N;
    scanf("%d", &N);
    int total_cost = 0;
    int pairs[N][2];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &pairs[i][0], &pairs[i][1]);
        total_cost += pairs[i][0] + pairs[i][1];
    }
    int dp[total_cost / 2 + 1];
    for (int i = 0; i <= total_cost / 2; i++) {
        dp[i] = INT_MAX;
    }
    dp[0] = 0;
    for (int i = 0; i < N; i++) {
        for (int j = total_cost / 2; j >= 0; j--) {
            if (j - pairs[i][0] >= 0) {
                dp[j] = min(dp[j], dp[j - pairs[i][0]] + pairs[i][1]);
            }
            if (j - pairs[i][1] >= 0) {
                dp[j] = min(dp[j], dp[j - pairs[i][1]] + pairs[i][0]);
            }
        }
    }
    int min_diff = INT_MAX;
    for (int i = 0; i <= total_cost / 2; i++) {
        if (dp[i] != INT_MAX) {
            min_diff = min(min_diff, abs(total_cost - 2 * i));
        }
    }
    printf("%d\n", min_diff);
    return 0;
}

