import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int total_cost = 0;
        int[][] pairs = new int[N][2];
        for (int i = 0; i < N; i++) {
            pairs[i][0] = sc.nextInt();
            pairs[i][1] = sc.nextInt();
            total_cost += pairs[i][0] + pairs[i][1];
        }
        int[] dp = new int[total_cost / 2 + 1];
        for (int i = 0; i <= total_cost / 2; i++) {
            dp[i] = Integer.MAX_VALUE;
        }
        dp[0] = 0;
        for (int i = 0; i < N; i++) {
            for (int j = total_cost / 2; j >= 0; j--) {
                if (j - pairs[i][0] >= 0) {
                    dp[j] = Math.min(dp[j], dp[j - pairs[i][0]] + pairs[i][1]);
                }
                if (j - pairs[i][1] >= 0) {
                    dp[j] = Math.min(dp[j], dp[j - pairs[i][1]] + pairs[i][0]);
                }
            }
        }
        int min_diff = Integer.MAX_VALUE;
        for (int i = 0; i <= total_cost / 2; i++) {
            if (dp[i] != Integer.MAX_VALUE) {
                min_diff = Math.min(min_diff, Math.abs(total_cost - 2 * i));
            }
        }
        System.out.println(min_diff);
    }
}

