const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];
const N = parseInt(readline());
let total_cost = 0;
const pairs = [];
for (let i = 0; i < N; i++) {
    const [a, b] = readline().split(' ').map(Number);
    total_cost += a + b;
    pairs.push([a, b]);
}
const dp = new Array(total_cost / 2 + 1).fill(Infinity);
dp[0] = 0;
for (const [a, b] of pairs) {
    for (let j = total_cost / 2; j >= 0; j--) {
        if (j - a >= 0) {
            dp[j] = Math.min(dp[j], dp[j - a] + b);
        }
        if (j - b >= 0) {
            dp[j] = Math.min(dp[j], dp[j - b] + a);
        }
    }
}
let min_diff = Infinity;
for (let i = 0; i <= total_cost / 2; i++) {
    if (dp[i] !== Infinity) {
        min_diff = Math.min(min_diff, Math.abs(total_cost - 2 * i));
    }
}
console.log(min_diff);

